### Configure PostHog in next.config.js

Source: https://github.com/posthog/posthog.com/blob/master/contents/docs/error-tracking/_snippets/nextjs-upload-source-maps.mdx

Update your `next.config.js` file to include PostHog configuration. This involves importing `withPostHogConfig` and passing your PostHog API key, environment ID, and optional sourcemap settings. This configuration enables the automatic upload of sourcemaps for production builds.

```javascript
import { withPostHogConfig } from "@posthog/nextjs-config";

const nextConfig = {
  //...your nextjs config,
};

export default withPostHogConfig(nextConfig, {
  personalApiKey: process.env.POSTHOG_API_KEY, // Personal API Key
  envId: process.env.POSTHOG_ENV_ID, // Environment ID
  host: process.env.NEXT_PUBLIC_POSTHOG_HOST, // (optional), defaults to https://us.posthog.com
  sourcemaps: { // (optional)
      enabled: true, // (optional) Enable sourcemaps generation and upload, default to true on production builds
      project: "my-application", // (optional) Project name, defaults to repository name
      version: "1.0.0", // (optional) Release version, defaults to current git commit
      deleteAfterUpload: true, // (optional) Delete sourcemaps after upload, defaults to true
  },
});

```

